import{_ as e,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Estatísticas de Token: Monitoramento de Custo e Análise de Dados | Antigravity Manager","description":"Aprenda como usar a funcionalidade de estatísticas Token Stats. Entenda como extrair dados de token de respostas, analisar uso por modelo e conta, e localizar os modelos e contas mais caros através de listas Top.","frontmatter":{"title":"Estatísticas de Token: Monitoramento de Custo e Análise de Dados | Antigravity Manager","sidebarTitle":"Veja quem é mais caro de relance","subtitle":"Estatísticas de Token: Monitoramento de Custo e Análise de Dados","description":"Aprenda como usar a funcionalidade de estatísticas Token Stats. Entenda como extrair dados de token de respostas, analisar uso por modelo e conta, e localizar os modelos e contas mais caros através de listas Top.","tags":["Token Stats","custo","monitoramento","SQLite","estatísticas de uso"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),s={name:"pt/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function d(i,a,n,c,l,u){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="token-stats-metricas-de-perspectiva-de-custo-e-interpretacao-de-graficos" tabindex="-1">Token Stats: Métricas de Perspectiva de Custo e Interpretação de Gráficos <a class="header-anchor" href="#token-stats-metricas-de-perspectiva-de-custo-e-interpretacao-de-graficos" aria-label="Permalink to &quot;Token Stats: Métricas de Perspectiva de Custo e Interpretação de Gráficos&quot;">​</a></h1><p>Você já conectou o cliente às Antigravity Tools, mas &quot;quem está gastando dinheiro, onde está caro, ou se um modelo de repente disparou&quot; geralmente é difícil de julgar por intuição. Esta aula faz apenas uma coisa: explicar claramente as métricas de dados na página Token Stats, e ensinar a usar gráficos para localizar rapidamente problemas de custo.</p><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Dizer claramente de onde vêm os dados do Token Stats (quando serão gravados, em que circunstâncias estarão ausentes)</li><li>Alternar janelas de observação por hora/dia/semana, evitando julgamento errado por &quot;ver apenas um dia&quot;</li><li>Em duas visualizações &quot;por modelo/por conta&quot;, usar gráficos de tendência para encontrar picos anormais</li><li>Usar listas Top para travar os modelos/contas mais caros, depois voltar aos logs de solicitação para encontrar a causa raiz</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Você sente que chamadas ficaram mais caras, mas não sabe se o modelo mudou, a conta mudou, ou se um dia o volume de repente aumentou</li><li>Você vê <code>X-Mapped-Model</code>, mas não tem certeza se a estatística é calculada por qual métrica de modelo</li><li>O Token Stats ocasionalmente mostra 0 ou &quot;sem dados&quot;, não sabe se é sem tráfego ou não foi estatizado</li></ul><h2 id="quando-usar-esta-estrategia" tabindex="-1">Quando usar esta estratégia <a class="header-anchor" href="#quando-usar-esta-estrategia" aria-label="Permalink to &quot;Quando usar esta estratégia&quot;">​</a></h2><ul><li>Você precisa fazer otimização de custo: primeiro quantifique &quot;quem é mais caro&quot;</li><li>Você está solucionando problemas de limitação/anomalia súbita: use o ponto de tempo de pico para comparar com logs de solicitação</li><li>Você fez mudanças de configuração em roteamento de modelo/governança de cota, e quer verificar se o custo caiu conforme esperado</li></ul><h2 id="o-que-e-token-stats" tabindex="-1">O que é Token Stats? <a class="header-anchor" href="#o-que-e-token-stats" aria-label="Permalink to &quot;O que é Token Stats?&quot;">​</a></h2><p><strong>Token Stats</strong> é a página de estatísticas de uso local das Antigravity Tools: após o proxy encaminhar solicitações, tentará extrair o número de token de <code>usage/usageMetadata</code> no JSON de resposta ou dados de streaming, e gravará cada solicitação por conta e modelo no SQLite local (<code>token_stats.db</code>), e finalmente mostrará agregações por tempo/modelo/conta na UI.</p><div class="info custom-block"><p class="custom-block-title">Primeiro esclareça um ponto fácil de tropeçar</p><p>A métrica de &quot;modelo&quot; do Token Stats vem do campo <code>model</code> em sua solicitação (ou parsing de caminho <code>/v1beta/models/&lt;model&gt;</code> do Gemini), não igual ao <code>X-Mapped-Model</code> após roteamento.</p></div><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><ul><li>Você já completou uma chamada de proxy com sucesso (não parou em <code>/healthz</code> probe)</li><li>Sua resposta upstream retornará campos de uso de token analisáveis (caso contrário, a estatística estará ausente)</li></ul><div class="tip custom-block"><p class="custom-block-title">Leitura recomendada conjunta</p><p>Se você está usando mapeamento de modelo para rotear <code>model</code> para outros modelos físicos, sugiro primeiro ver <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/advanced/model-router/">Roteamento de modelo: mapeamento personalizado, prioridade de curinga e estratégias predefinidas</a></strong>, depois voltar para &quot;métricas de estatísticas&quot; será mais intuitivo.</p></div><h2 id="ideia-central" tabindex="-1">Ideia central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia central&quot;">​</a></h2><p>A cadeia de dados do Token Stats pode ser dividida em três segmentos:</p><ol><li>Middleware de proxy tenta extrair uso de token da resposta (compatível com <code>usage</code>/<code>usageMetadata</code>, streaming também analisará)</li><li>Se ao mesmo tempo obtiver <code>account_email + input_tokens + output_tokens</code>, gravará no SQLite local (<code>token_stats.db</code>)</li><li>UI puxa dados agregados através de Tauri <code>invoke(get_token_stats_*)</code>, mostrando por hora/dia/semana</li></ol><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-primeiro-confirme-que-voce-tem-trafego" tabindex="-1">Passo 1: Primeiro, confirme que &quot;você tem tráfego&quot; <a class="header-anchor" href="#passo-1-primeiro-confirme-que-voce-tem-trafego" aria-label="Permalink to &quot;Passo 1: Primeiro, confirme que &quot;você tem tráfego&quot;&quot;">​</a></h3><p><strong>Por que</strong> Estatísticas do Token Stats vêm de solicitações reais. Apenas iniciar o proxy mas nunca enviar uma solicitação de modelo, a página mostrará &quot;sem dados&quot;.</p><p>Prática: Reutilize o método de chamada que você já verificou com sucesso em <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Iniciar proxy reverso local e conectar o primeiro cliente</a></strong>, envie 1-2 solicitações.</p><p><strong>Você deve ver</strong>: A página Token Stats muda de &quot;carregando/sem dados&quot; para ter gráficos ou listas.</p><h3 id="passo-2-escolha-a-janela-de-tempo-correta-hora-dia-semana" tabindex="-1">Passo 2: Escolha a janela de tempo correta (hora/dia/semana) <a class="header-anchor" href="#passo-2-escolha-a-janela-de-tempo-correta-hora-dia-semana" aria-label="Permalink to &quot;Passo 2: Escolha a janela de tempo correta (hora/dia/semana)&quot;">​</a></h3><p><strong>Por que</strong> O mesmo conjunto de dados em diferentes janelas mostra &quot;pico/tendência&quot; completamente diferente. As três janelas na UI também correspondem a diferentes intervalos de coleta de dados:</p><ul><li>Hora: últimas 24 horas</li><li>Dia: últimos 7 dias</li><li>Semana: últimas 4 semanas (visualização de tendência agregará nos últimos 30 dias)</li></ul><p><strong>Você deve ver</strong>: Após alternar, a granularidade do eixo X do gráfico de tendência muda (hora mostra &quot;hora&quot;, dia mostra &quot;mês/dia&quot;, semana mostra &quot;ano-Wnúmero-semana&quot;).</p><h3 id="passo-3-primeiro-veja-a-visao-geral-superior-determine-a-escala-de-custo" tabindex="-1">Passo 3: Primeiro veja a visão geral superior, determine a &quot;escala de custo&quot; <a class="header-anchor" href="#passo-3-primeiro-veja-a-visao-geral-superior-determine-a-escala-de-custo" aria-label="Permalink to &quot;Passo 3: Primeiro veja a visão geral superior, determine a &quot;escala de custo&quot;&quot;">​</a></h3><p><strong>Por que</strong> O cartão de visão geral pode primeiro responder a 3 perguntas: se o volume total é grande, se a proporção entrada/saída é anormal, se o número de contas/modelos participantes de repente aumentou.</p><p>Foque nestes itens:</p><ul><li>Total de Tokens (<code>total_tokens</code>)</li><li>Tokens de Entrada/Saída (<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>Número de contas ativas (<code>unique_accounts</code>)</li><li>Número de modelos usados (UI usa diretamente o comprimento da &quot;lista de estatísticas por modelo&quot;)</li></ul><p><strong>Você deve ver</strong>: Se o &quot;número de contas ativas&quot; de repente aumentar muito, geralmente significa que você rodou mais contas em pouco tempo (por exemplo, mudou para estratégia de rotação).</p><h3 id="passo-4-use-tendencia-de-uso-por-modelo-por-conta-para-capturar-picos-anormais" tabindex="-1">Passo 4: Use &quot;tendência de uso por modelo/por conta&quot; para capturar picos anormais <a class="header-anchor" href="#passo-4-use-tendencia-de-uso-por-modelo-por-conta-para-capturar-picos-anormais" aria-label="Permalink to &quot;Passo 4: Use &quot;tendência de uso por modelo/por conta&quot; para capturar picos anormais&quot;">​</a></h3><p><strong>Por que</strong> O gráfico de tendência é o ponto de entrada mais adequado para capturar &quot;de repente ficou caro&quot;. Você não precisa primeiro saber a causa, primeiro circule &quot;que dia/qual hora disparou&quot;.</p><p>Prática:</p><ol><li>No canto superior direito do gráfico de tendência, mude para「Por modelo / Por conta」</li><li>Passe o mouse (Tooltip) para ver o valor Top, priorize prestar atenção naquele que &quot;de repente chegou ao primeiro lugar&quot;</li></ol><p><strong>Você deve ver</strong>:</p><ul><li>Por modelo: um modelo subiu de repente em um período de tempo específico</li><li>Por conta: uma conta subiu de repente em um período de tempo específico</li></ul><h3 id="passo-5-use-a-lista-top-para-travar-o-alvo-mais-caro" tabindex="-1">Passo 5: Use a lista Top para &quot;travar o alvo mais caro&quot; <a class="header-anchor" href="#passo-5-use-a-lista-top-para-travar-o-alvo-mais-caro" aria-label="Permalink to &quot;Passo 5: Use a lista Top para &quot;travar o alvo mais caro&quot;&quot;">​</a></h3><p><strong>Por que</strong> O gráfico de tendência diz &quot;quando anômalo&quot;, a lista Top diz &quot;quem é mais caro&quot;. Cruzando os dois, você pode rapidamente delimitar o escopo de solução de problemas.</p><p>Prática:</p><ul><li>Na visualização「Por modelo」, veja a tabela &quot;estatísticas detalhadas por modelo&quot; com <code>total_tokens / request_count / proporção</code></li><li>Na visualização「Por conta」, veja a tabela &quot;estatísticas detalhadas de conta&quot; com <code>total_tokens / request_count</code></li></ul><p><strong>Você deve ver</strong>: Os modelos/contas mais caros ficam na frente, e <code>request_count</code> pode ajudá-lo a distinguir &quot;único particularmente caro&quot; ou &quot;muitos 特别多&quot;.</p><h3 id="passo-6-opcional-encontre-token-stats-db-faca-backup-verificacao" tabindex="-1">Passo 6 (opcional): Encontre <code>token_stats.db</code>, faça backup/verificação <a class="header-anchor" href="#passo-6-opcional-encontre-token-stats-db-faca-backup-verificacao" aria-label="Permalink to &quot;Passo 6 (opcional): Encontre `token_stats.db`, faça backup/verificação&quot;">​</a></h3><p><strong>Por que</strong> Quando você suspeita de &quot;estatísticas ausentes&quot; ou quer fazer análise offline, pegar o arquivo SQLite diretamente é mais confiável.</p><p>Prática: Entre na área Advanced de Settings, clique &quot;Abrir diretório de dados&quot;, você encontrará <code>token_stats.db</code> no diretório de dados.</p><p><strong>Você deve ver</strong>: Na lista de arquivos há <code>token_stats.db</code> (o nome do arquivo é codificado no backend).</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>Você pode explicar claramente que a estatística do Token Stats é &quot;extraída do usage/usageMetadata da resposta e gravada no SQLite local&quot;, não faturamento na nuvem</li><li>Você pode apontar um período de pico específico em duas visualizações de tendência &quot;por modelo/por conta&quot;</li><li>Você pode dar uma conclusão de solução de problemas executável usando a lista Top: primeiro verificar qual modelo ou conta</li></ul><h2 id="avisos-sobre-armadilhas" tabindex="-1">Avisos sobre armadilhas <a class="header-anchor" href="#avisos-sobre-armadilhas" aria-label="Permalink to &quot;Avisos sobre armadilhas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenômeno</th><th>Causa comum</th><th>O que você pode fazer</th></tr></thead><tbody><tr><td>Token Stats mostra &quot;sem dados&quot;</td><td>Você realmente não gerou solicitações de modelo; ou a resposta upstream não carrega campos de token analisáveis</td><td>Primeiro reutilize o cliente já verificado para enviar solicitações; depois veja se a resposta contém <code>usage/usageMetadata</code></td></tr><tr><td>Estatísticas parecem erradas &quot;por modelo&quot;</td><td>Métricas estatísticas usam <code>model</code> da solicitação, não <code>X-Mapped-Model</code></td><td>Trate roteamento de modelo como &quot;solicitar modelo -&gt; modelo mapeado&quot;; estatísticas veem &quot;modelo solicitado&quot;</td></tr><tr><td>Dimensão de conta ausente</td><td>Só será gravado quando obtiver <code>X-Account-Email</code> e analisar uso de token</td><td>Confirme que a solicitação realmente chegou ao pool de contas; depois compare logs de solicitação/cabeçalhos de resposta</td></tr><tr><td>Dados estatísticos desviados ao ativar Proxy Monitor</td><td>Quando Proxy Monitor ativado, token de cada solicitação será gravado duas vezes</td><td>Este é um detalhe de implementação conhecido, não afeta análise de tendência relativa; se precisar de valor exato, pode desativar Monitor temporariamente e retestar</td></tr></tbody></table><h2 id="resumo-desta-aula" tabindex="-1">Resumo desta aula <a class="header-anchor" href="#resumo-desta-aula" aria-label="Permalink to &quot;Resumo desta aula&quot;">​</a></h2><ul><li>O valor central do Token Stats é &quot;quantificar problemas de custo&quot;, primeiro localizar, depois otimizar</li><li>Ao gravar estatísticas, conta e uso de token são obrigatórios; quando modelo ausente será gravado como <code>&quot;unknown&quot;</code> (não bloqueará gravação)</li><li>Para fazer controle de custo mais refinado, geralmente o próximo passo é voltar ao roteamento de modelo ou governança de cota</li></ul><h2 id="proxima-aula" tabindex="-1">Próxima aula <a class="header-anchor" href="#proxima-aula" aria-label="Permalink to &quot;Próxima aula&quot;">​</a></h2><blockquote><p>Na próxima aula, resolvemos &quot;problemas de estabilidade ocultos&quot; em sessões longas: <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/advanced/context-compression/">Estabilidade de sessão longa: compressão de contexto, cache de assinatura e compressão de resultados de ferramenta</a></strong>.</p></blockquote><p>Você aprenderá:</p><ul><li>O que as três camadas de compressão progressiva de contexto fazem respectivamente</li><li>Por que &quot;cache de assinatura&quot; pode reduzir erros de assinatura 400</li><li>O que a compressão de resultados de ferramenta deletará, o que manterá</li></ul><hr><h2 id="apendice-referencias-de-codigo-fonte" tabindex="-1">Apêndice: Referências de código-fonte <a class="header-anchor" href="#apendice-referencias-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referências de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localizações do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>UI do Token Stats: janela de tempo/alternância de visualização e coleta de dados</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>UI do Token Stats: prompt de dados vazios (&quot;sem dados&quot;)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Extração de uso de Token: analisar model da solicitação, analisar usage/usageMetadata da resposta</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Extração de uso de Token: analisar campo usage de resposta de streaming/JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Ponto de gravação de Token Stats: gravar no SQLite após obter conta+token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>Nome do arquivo de banco de dados e estrutura da tabela: <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>Lógica de gravação: <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>Lógica de consulta: hora/dia/semana, por conta/por modelo, tendência e visão geral</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Comandos Tauri: <code>get_token_stats_*</code> expostos para frontend</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>Ao iniciar aplicativo, inicializar banco de dados do Token Stats</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>Página de Configurações: obter/abrir diretório de dados (para encontrar <code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const g=e(s,[["render",d]]);export{p as __pageData,g as default};
